INSERT OR REPLACE INTO security_controls (id, framework_id, control_id, family, title, description, priority, baseline_low, baseline_moderate, baseline_high, is_enhancement, parent_control_id, sort_order) VALUES (lower(hex(randomblob(16))), 'fw_soc2', 'CC1.1', 'Control Environment', 'COSO Principle 1', 'The entity demonstrates a commitment to integrity and ethical values.', 'P1', 1, 1, 1, 0, '', 1);
INSERT OR REPLACE INTO security_controls (id, framework_id, control_id, family, title, description, priority, baseline_low, baseline_moderate, baseline_high, is_enhancement, parent_control_id, sort_order) VALUES (lower(hex(randomblob(16))), 'fw_soc2', 'CC1.2', 'Control Environment', 'COSO Principle 2', 'The board of directors demonstrates independence from management and exercises oversight of the development and performance of internal control.', 'P1', 1, 1, 1, 0, '', 2);
INSERT OR REPLACE INTO security_controls (id, framework_id, control_id, family, title, description, priority, baseline_low, baseline_moderate, baseline_high, is_enhancement, parent_control_id, sort_order) VALUES (lower(hex(randomblob(16))), 'fw_soc2', 'CC1.3', 'Control Environment', 'COSO Principle 3', 'Management establishes, with board oversight, structures, reporting lines, and appropriate authorities and responsibilities.', 'P1', 1, 1, 1, 0, '', 3);
INSERT OR REPLACE INTO security_controls (id, framework_id, control_id, family, title, description, priority, baseline_low, baseline_moderate, baseline_high, is_enhancement, parent_control_id, sort_order) VALUES (lower(hex(randomblob(16))), 'fw_soc2', 'CC1.4', 'Control Environment', 'COSO Principle 4', 'The entity demonstrates a commitment to attract, develop, and retain competent individuals in alignment with objectives.', 'P1', 1, 1, 1, 0, '', 4);
INSERT OR REPLACE INTO security_controls (id, framework_id, control_id, family, title, description, priority, baseline_low, baseline_moderate, baseline_high, is_enhancement, parent_control_id, sort_order) VALUES (lower(hex(randomblob(16))), 'fw_soc2', 'CC1.5', 'Control Environment', 'COSO Principle 5', 'The entity holds individuals accountable for their internal control responsibilities in the pursuit of objectives.', 'P1', 1, 1, 1, 0, '', 5);
INSERT OR REPLACE INTO security_controls (id, framework_id, control_id, family, title, description, priority, baseline_low, baseline_moderate, baseline_high, is_enhancement, parent_control_id, sort_order) VALUES (lower(hex(randomblob(16))), 'fw_soc2', 'CC2.1', 'Communication and Information', 'COSO Principle 13', 'The entity obtains or generates and uses relevant, quality information to support the functioning of internal control.', 'P1', 1, 1, 1, 0, '', 6);
INSERT OR REPLACE INTO security_controls (id, framework_id, control_id, family, title, description, priority, baseline_low, baseline_moderate, baseline_high, is_enhancement, parent_control_id, sort_order) VALUES (lower(hex(randomblob(16))), 'fw_soc2', 'CC2.2', 'Communication and Information', 'COSO Principle 14', 'The entity internally communicates information, including objectives and responsibilities for internal control.', 'P1', 1, 1, 1, 0, '', 7);
INSERT OR REPLACE INTO security_controls (id, framework_id, control_id, family, title, description, priority, baseline_low, baseline_moderate, baseline_high, is_enhancement, parent_control_id, sort_order) VALUES (lower(hex(randomblob(16))), 'fw_soc2', 'CC2.3', 'Communication and Information', 'COSO Principle 15', 'The entity communicates with external parties regarding matters affecting the functioning of internal control.', 'P1', 1, 1, 1, 0, '', 8);
INSERT OR REPLACE INTO security_controls (id, framework_id, control_id, family, title, description, priority, baseline_low, baseline_moderate, baseline_high, is_enhancement, parent_control_id, sort_order) VALUES (lower(hex(randomblob(16))), 'fw_soc2', 'CC3.1', 'Risk Assessment', 'COSO Principle 6', 'The entity specifies objectives with sufficient clarity to enable the identification and assessment of risks relating to objectives.', 'P1', 1, 1, 1, 0, '', 9);
INSERT OR REPLACE INTO security_controls (id, framework_id, control_id, family, title, description, priority, baseline_low, baseline_moderate, baseline_high, is_enhancement, parent_control_id, sort_order) VALUES (lower(hex(randomblob(16))), 'fw_soc2', 'CC3.2', 'Risk Assessment', 'COSO Principle 7', 'The entity identifies risks to the achievement of its objectives across the entity and analyzes risks as a basis for determining how the risks should be managed.', 'P1', 1, 1, 1, 0, '', 10);
INSERT OR REPLACE INTO security_controls (id, framework_id, control_id, family, title, description, priority, baseline_low, baseline_moderate, baseline_high, is_enhancement, parent_control_id, sort_order) VALUES (lower(hex(randomblob(16))), 'fw_soc2', 'CC3.3', 'Risk Assessment', 'COSO Principle 8', 'The entity considers the potential for fraud in assessing risks to the achievement of objectives.', 'P1', 1, 1, 1, 0, '', 11);
INSERT OR REPLACE INTO security_controls (id, framework_id, control_id, family, title, description, priority, baseline_low, baseline_moderate, baseline_high, is_enhancement, parent_control_id, sort_order) VALUES (lower(hex(randomblob(16))), 'fw_soc2', 'CC3.4', 'Risk Assessment', 'COSO Principle 9', 'The entity identifies and assesses changes that could significantly impact the system of internal control.', 'P1', 1, 1, 1, 0, '', 12);
INSERT OR REPLACE INTO security_controls (id, framework_id, control_id, family, title, description, priority, baseline_low, baseline_moderate, baseline_high, is_enhancement, parent_control_id, sort_order) VALUES (lower(hex(randomblob(16))), 'fw_soc2', 'CC4.1', 'Monitoring Activities', 'COSO Principle 16', 'The entity selects, develops, and performs ongoing and/or separate evaluations to ascertain whether the components of internal control are present and functioning.', 'P1', 1, 1, 1, 0, '', 13);
INSERT OR REPLACE INTO security_controls (id, framework_id, control_id, family, title, description, priority, baseline_low, baseline_moderate, baseline_high, is_enhancement, parent_control_id, sort_order) VALUES (lower(hex(randomblob(16))), 'fw_soc2', 'CC4.2', 'Monitoring Activities', 'COSO Principle 17', 'The entity evaluates and communicates internal control deficiencies in a timely manner to those parties responsible.', 'P1', 1, 1, 1, 0, '', 14);
INSERT OR REPLACE INTO security_controls (id, framework_id, control_id, family, title, description, priority, baseline_low, baseline_moderate, baseline_high, is_enhancement, parent_control_id, sort_order) VALUES (lower(hex(randomblob(16))), 'fw_soc2', 'CC5.1', 'Control Activities', 'COSO Principle 10', 'The entity selects and develops control activities that contribute to the mitigation of risks to the achievement of objectives.', 'P1', 1, 1, 1, 0, '', 15);
INSERT OR REPLACE INTO security_controls (id, framework_id, control_id, family, title, description, priority, baseline_low, baseline_moderate, baseline_high, is_enhancement, parent_control_id, sort_order) VALUES (lower(hex(randomblob(16))), 'fw_soc2', 'CC5.2', 'Control Activities', 'COSO Principle 11', 'The entity also selects and develops general control activities over technology to support the achievement of objectives.', 'P1', 1, 1, 1, 0, '', 16);
INSERT OR REPLACE INTO security_controls (id, framework_id, control_id, family, title, description, priority, baseline_low, baseline_moderate, baseline_high, is_enhancement, parent_control_id, sort_order) VALUES (lower(hex(randomblob(16))), 'fw_soc2', 'CC5.3', 'Control Activities', 'COSO Principle 12', 'The entity deploys control activities through policies that establish what is expected and in procedures that put policies into action.', 'P1', 1, 1, 1, 0, '', 17);
INSERT OR REPLACE INTO security_controls (id, framework_id, control_id, family, title, description, priority, baseline_low, baseline_moderate, baseline_high, is_enhancement, parent_control_id, sort_order) VALUES (lower(hex(randomblob(16))), 'fw_soc2', 'CC6.1', 'Logical and Physical Access Controls', 'Logical Access Security', 'The entity implements logical access security software, infrastructure, and architectures over protected information assets to protect them from security events.', 'P1', 1, 1, 1, 0, '', 18);
INSERT OR REPLACE INTO security_controls (id, framework_id, control_id, family, title, description, priority, baseline_low, baseline_moderate, baseline_high, is_enhancement, parent_control_id, sort_order) VALUES (lower(hex(randomblob(16))), 'fw_soc2', 'CC6.2', 'Logical and Physical Access Controls', 'User Registration and Authorization', 'Prior to issuing system credentials and granting system access, the entity registers and authorizes new internal and external users.', 'P1', 1, 1, 1, 0, '', 19);
INSERT OR REPLACE INTO security_controls (id, framework_id, control_id, family, title, description, priority, baseline_low, baseline_moderate, baseline_high, is_enhancement, parent_control_id, sort_order) VALUES (lower(hex(randomblob(16))), 'fw_soc2', 'CC6.3', 'Logical and Physical Access Controls', 'Role-Based Access and Least Privilege', 'The entity authorizes, modifies, or removes access to data, software, functions, and other protected information assets based on roles.', 'P1', 1, 1, 1, 0, '', 20);
INSERT OR REPLACE INTO security_controls (id, framework_id, control_id, family, title, description, priority, baseline_low, baseline_moderate, baseline_high, is_enhancement, parent_control_id, sort_order) VALUES (lower(hex(randomblob(16))), 'fw_soc2', 'CC6.4', 'Logical and Physical Access Controls', 'Physical Access Restrictions', 'The entity restricts physical access to facilities and protected information assets to authorized personnel.', 'P1', 1, 1, 1, 0, '', 21);
INSERT OR REPLACE INTO security_controls (id, framework_id, control_id, family, title, description, priority, baseline_low, baseline_moderate, baseline_high, is_enhancement, parent_control_id, sort_order) VALUES (lower(hex(randomblob(16))), 'fw_soc2', 'CC6.5', 'Logical and Physical Access Controls', 'Logical Access Disposal', 'The entity discontinues logical and physical protections over physical assets only after the ability to read or recover data has been diminished.', 'P1', 1, 1, 1, 0, '', 22);
